import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, CUSTOM_ELEMENTS_SCHEMA, Input, ViewChild, } from '@angular/core';
import { defineUpupElement } from '@upup/vanilla';
import { upupAngularAttributes } from './upup-angular-attributes';
let UpupUploaderComponent = class UpupUploaderComponent {
    constructor() {
        this.viewReady = false;
    }
    ngAfterViewInit() {
        defineUpupElement();
        this.viewReady = true;
        this.applyAttributes();
    }
    ngOnChanges() {
        if (this.viewReady) {
            this.applyAttributes();
        }
    }
    applyAttributes() {
        const element = this.uploader?.nativeElement;
        if (!element)
            return;
        for (const [name, value] of Object.entries(upupAngularAttributes(this))) {
            if (value === undefined || value === null) {
                element.removeAttribute(name);
            }
            else {
                element.setAttribute(name, String(value));
            }
        }
    }
    static { this.propDecorators = {
        uploadEndpoint: [{ type: Input }],
        serverUrl: [{ type: Input }],
        mode: [{ type: Input }],
        sources: [{ type: Input }],
        maxFiles: [{ type: Input }],
        accept: [{ type: Input }],
        enablePaste: [{ type: Input }],
        theme: [{ type: Input }],
        locale: [{ type: Input }],
        dir: [{ type: Input }],
        uploader: [{ type: ViewChild, args: ['uploader', { static: true },] }]
    }; }
};
UpupUploaderComponent = __decorate([
    Component({
        selector: 'upup-uploader-angular',
        standalone: true,
        schemas: [CUSTOM_ELEMENTS_SCHEMA],
        changeDetection: ChangeDetectionStrategy.OnPush,
        template: '<upup-uploader #uploader><ng-content /></upup-uploader>',
    })
], UpupUploaderComponent);
export { UpupUploaderComponent };
